// Parse and validate the Gemini extraction response
const geminiResponse = $input.first().json;
const webhookData = $('Webhook Trigger').first().json;

const requiredFields = [
  'document_type', 'effective_date', 'expiration_date',
  'parties', 'jurisdiction', 'key_clauses', 'summary'
];

let metadata = {};
let validationErrors = [];

try {
  const text = geminiResponse.candidates[0].content.parts[0].text;
  const cleaned = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  metadata = JSON.parse(cleaned);
} catch (e) {
  validationErrors.push(`JSON parse error: ${e.message}`);
  metadata = {};
}

// Validate required fields
for (const field of requiredFields) {
  if (!metadata[field] && metadata[field] !== 0) {
    validationErrors.push(`Missing required field: ${field}`);
  }
}

// Validate date formats
const dateFields = ['effective_date', 'expiration_date', 'renewal_date'];
for (const df of dateFields) {
  if (metadata[df]) {
    const parsed = new Date(metadata[df]);
    if (isNaN(parsed.getTime())) {
      validationErrors.push(`Invalid date format for ${df}: ${metadata[df]}`);
      metadata[df] = null;
    }
  }
}

// Validate risk flags severity
if (Array.isArray(metadata.risk_flags)) {
  metadata.risk_flags = metadata.risk_flags.map(flag => ({
    ...flag,
    severity: Math.min(5, Math.max(1, parseInt(flag.severity) || 3))
  }));
}

// Ensure arrays are actually arrays
const arrayFields = ['parties', 'key_clauses', 'monetary_amounts', 'compliance_requirements',
  'regulatory_references', 'risk_flags', 'termination_conditions', 'amendment_history',
  'signatures', 'special_conditions'];
for (const af of arrayFields) {
  if (metadata[af] && !Array.isArray(metadata[af])) {
    metadata[af] = [metadata[af]];
  } else if (!metadata[af]) {
    metadata[af] = [];
  }
}

// Set confidence based on validation
if (!metadata.confidence_score) {
  metadata.confidence_score = validationErrors.length === 0 ? 0.9 : Math.max(0.1, 0.9 - (validationErrors.length * 0.1));
}

return [{
  json: {
    document_id: webhookData.document_id,
    entity_id: webhookData.entity_id,
    metadata: metadata,
    validation_errors: validationErrors,
    is_valid: validationErrors.length === 0,
    extracted_at: new Date().toISOString()
  }
}];
